def fibonacci(n):
    a, b = 0, 1
    for _ in range(n):
        yield a
        a, b = b, a + b

def fib(n: int) -> int:
    # Dictionary to store the results of subproblems
    memo = {0: 0, 1: 1}

    def helper(x):
        if x in memo:
            return memo[x]

        # Calculate the Fibonacci number using recursion and memoization
        result = helper(x-1) + helper(x-2)
        memo[x] = result
        return result

    # Call the helper function with the input n
    return helper(n)

# Test cases
print(fib(10))  # Output: 55
print(fib(1))   # Output: 1
print(fib(8))   # Output: 21

def largest_prime_factor(n: int):
    """Return the largest prime factor of n. Assume n > 1 and is not a prime."""
    # Remove all even factors
    while n % 2 == 0:
        n //= 2

    # Check for odd factors starting from 3
    for i in range(3, int(n**0.5) + 1, 2):
        while n % i == 0:
            n //= i

    # If n is a prime number greater than 2
    if n > 2:
        return n

# Test cases
