print(largest_prime_factor(2048))  # Output: 2

def search(lst):
    # Count the frequency of each integer in the list
    freq = {}
    for num in lst:
        if num in freq:
            freq[num] += 1
        else:
            freq[num] = 1

    # Check for valid integers and return the result
    for num, count in freq.items():
        if num <= count:
            return num
    return -1

# Test cases
