def count_up_to(n):
    if n <= 0:
        return []

    primes = []
    for num in range(2, n):
        if is_prime(num):
            primes.append(num)

    return primes

def is_prime(num):
    if num <= 1:
        return False
    if num == 2:
        return True
    if num % 2 == 0:
        return False

    for i in range(3, int(math.sqrt(num)) + 1, 2):
        if num % i == 0:
            return False

    return True

